51	    NGX_MODULE_V1,
52	    &ngx_poll_module_ctx,                  /* module context */
53	    NULL,                                  /* module directives */
54	    NGX_EVENT_MODULE,                      /* module type */
55	    NULL,                                  /* init master */
56	    NULL,                                  /* init module */
57	    NULL,                                  /* init process */
58	    NULL,                                  /* init thread */
59	    NULL,                                  /* exit thread */
60	    NULL,                                  /* exit process */
61	    NULL,                                  /* exit master */
62	    NGX_MODULE_V1_PADDING
63	};
